package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnCommentSubmitProxy struct {
	automation.UnimplementedOnCommentSubmitServer
	client automation.OnCommentSubmitClient
}

func init() {
	proxyutil.Register(&automation.OnCommentSubmit_ServiceDesc, NewOnCommentSubmitProxy)
}
func NewOnCommentSubmitProxy(cc grpc.ClientConnInterface) automation.OnCommentSubmitServer {
	return &OnCommentSubmitProxy{client: automation.NewOnCommentSubmitClient(cc)}
}
func (p *OnCommentSubmitProxy) OnCommentSubmit(ctx context.Context, in *events.CommentSubmit) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.CommentSubmit, automation.HandlerResult](p.client.OnCommentSubmit)(ctx, in)
}
